import{_ as a,c as l,o as r,ah as i}from"./chunks/framework.Cnj7lwEt.js";const c=JSON.parse('{"title":"superpowers","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/superpowers-AI工具.md","filePath":"github汇总/AI工具/superpowers-AI工具.md"}'),o={name:"github汇总/AI工具/superpowers-AI工具.md"};function s(t,e,h,n,p,d){return r(),l("div",null,e[0]||(e[0]=[i('<h1 id="superpowers" tabindex="-1">superpowers <a class="header-anchor" href="#superpowers" aria-label="Permalink to “superpowers”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>superpowers</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>obra</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>AI工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>AI编码代理经常直接跳进写代码，缺乏系统规划，容易偏离目标。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>为编码代理提供完整的软件开发工作流，基于可组合的技能集构建。包含头脑风暴技能（将模糊想法变成清晰设计）、使用Git工作树技能（创建隔离工作空间）、编写计划技能（将工作分解为小任务）、子代理驱动开发技能（按计划执行任务）、测试驱动开发技能（红绿重构循环）、请求代码审查技能、完成开发分支技能。技能自动触发，无需手动调用。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>技能自动触发，无需手动调用</li><li>完整的软件开发工作流</li><li>强调测试驱动开发</li><li>支持多种AI编码工具（Claude Code、Cursor、Codex、OpenCode、Gemini CLI）</li><li>子代理驱动开发，可自主工作数小时</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/obra/superpowers" target="_blank" rel="noreferrer">https://github.com/obra/superpowers</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要为AI编码工具安装Superpowers技能的用户。</p><h3 id="主路径-claude-code官方市场安装" tabindex="-1">主路径：Claude Code官方市场安装 <a class="header-anchor" href="#主路径-claude-code官方市场安装" aria-label="Permalink to “主路径：Claude Code官方市场安装”">​</a></h3><p><strong>步骤1：打开Claude Code</strong></p><ul><li>目标：启动Claude Code</li><li>位置：终端</li><li>操作：运行 <code>claude</code> 命令</li><li>成功标志：Claude Code启动成功</li><li>失败处理：确认Claude Code已正确安装</li></ul><p><strong>步骤2：安装插件</strong></p><ul><li>目标：从官方市场安装Superpowers</li><li>位置：Claude Code</li><li>命令：<code>/plugin install superpowers@claude-plugins-official</code></li><li>成功标志：插件安装成功提示</li><li>失败处理：检查网络连接 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><h3 id="备选路径1-cursor安装" tabindex="-1">备选路径1：Cursor安装 <a class="header-anchor" href="#备选路径1-cursor安装" aria-label="Permalink to “备选路径1：Cursor安装”">​</a></h3><p><strong>步骤1：打开Cursor</strong></p><ul><li>目标：启动Cursor编辑器</li><li>位置：桌面或应用菜单</li><li>操作：打开Cursor</li><li>成功标志：Cursor启动成功</li><li>失败处理：确认Cursor已安装</li></ul><p><strong>步骤2：安装插件</strong></p><ul><li>目标：从市场安装Superpowers</li><li>位置：Cursor Agent聊天</li><li>命令：<code>/add-plugin superpowers</code></li><li>成功标志：插件安装成功</li><li>失败处理：检查网络连接</li></ul><h3 id="备选路径2-gemini-cli安装" tabindex="-1">备选路径2：Gemini CLI安装 <a class="header-anchor" href="#备选路径2-gemini-cli安装" aria-label="Permalink to “备选路径2：Gemini CLI安装”">​</a></h3><p><strong>步骤1：打开终端</strong></p><ul><li>目标：准备安装命令</li><li>位置：终端</li><li>操作：打开终端窗口</li><li>成功标志：终端就绪</li><li>失败处理：无</li></ul><p><strong>步骤2：安装扩展</strong></p><ul><li>目标：安装Superpowers扩展</li><li>位置：终端</li><li>命令：<code>gemini extensions install https://github.com/obra/superpowers</code></li><li>成功标志：扩展安装成功</li><li>失败处理：检查Gemini CLI是否正确安装</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>启动新的会话</li><li>请求帮助规划功能或调试问题</li><li>代理应该自动调用相关的superpowers技能</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>插件安装失败</strong></p><ul><li>可能原因：网络问题</li><li>解决步骤：检查网络连接，配置代理</li></ul></li><li><p><strong>技能不触发</strong></p><ul><li>可能原因：插件未正确加载</li><li>解决步骤：重启AI编码工具，重新安装插件</li></ul></li><li><p><strong>命令不被识别</strong></p><ul><li>可能原因：AI工具版本过低</li><li>解决步骤：更新AI编码工具到最新版本</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://github.com/obra/superpowers" target="_blank" rel="noreferrer">Superpowers Documentation</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',41)]))}const b=a(o,[["render",s]]);export{c as __pageData,b as default};
